mapper.select:


where bo.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and bo.id = #{id}
limit 1

select bo.id, bo.biz_order_no as bizOrderNo, bo.app_code as appCode, bo.title, bo.subject_id as subjectId, bo.amount, bo.paid_amount as paidAmount, bo.refunded_amount as refundedAmount, bo.currency, bo.status, bo.expire_time as expireTime, bo.notify_url as notifyUrl, bo.return_url as returnUrl, bo.extend_info as extendInfo, bo.tenant_id as tenantId, bo.created_by as createdBy, bo.created_at as createdAt, bo.updated_by as updatedBy, bo.updated_at as updatedAt, bo.del_flag as delFlag from payment_business_order bo where bo.tenant_id = #{tenantId} and bo.del_flag = 0 and bo.app_code in (#{appId}, #{legacyAppCode}) and bo.subject_id in
#{subjectId}
and bo.status in ('TO_PAY', 'PAYING') and (bo.expire_time is null or bo.expire_time > now()) order by bo.created_at desc limit 1
